#include <stdio.h>
int maxProfit(int* prices, int pricesSize, int k) {
    int dp[pricesSize][2][k + 1];
    for (int i = 0; i < pricesSize; i++) {
        for (int j = 0; j < 2; j++) {
            for (int l = 0; l <= k; l++) {
                dp[i][j][l] = -1;
            }
        }
    }
    return getAns(prices, pricesSize, 0, 0, k, dp);
}

int getAns(int* prices, int n, int ind, int buy, int cap, int*** dp) {
    if (ind == n || cap == 0) return 0;
    if (dp[ind][buy][cap] != -1) return dp[ind][buy][cap];
    int profit;
    if (buy == 0) {
        profit = max(0 + getAns(prices, n, ind + 1, 0, cap, dp), -prices[ind] + getAns(prices, n, ind + 1, 1, cap, dp));
    } else {
        profit = max(0 + getAns(prices, n, ind + 1, 1, cap, dp), prices[ind] + getAns(prices, n, ind + 1, 0, cap - 1, dp));
    }
    dp[ind][buy][cap] = profit;
    return profit;
}

