class StockBuySell{
    function maximumProfit(prices, n, k) {
        // Creating a 3D array dp of size [n][2][k+1] and initializing with -1
        let dp = new Array(n);
        for (let i = 0; i < n; i++) {
            dp[i] = new Array(2);
            for (let j = 0; j < 2; j++) {
                dp[i][j] = new Array(k + 1).fill(-1);
            }
        }

        // Define a recursive function to calculate maximum profit
        function getAns(ind, buy, cap) {
            // Base case
            if (ind === n || cap === 0) return 0;

            // Check if the result is already computed and stored in dp
            if (dp[ind][buy][cap] !== -1) return dp[ind][buy][cap];

            let profit;

            if (buy === 0) { // We can buy the stock
                profit = Math.max(
                    0 + getAns(ind + 1, 0, cap),
                    -prices[ind] + getAns(ind + 1, 1, cap)
                );
            }

            if (buy === 1) { // We can sell the stock
                profit = Math.max(
                    0 + getAns(ind + 1, 1, cap),
                    prices[ind] + getAns(ind + 1, 0, cap - 1)
                );
            }

            // Store the result in dp and return it
            dp[ind][buy][cap] = profit;
            return profit;
        }

        // Call the recursive function to compute the maximum profit
        return getAns(0, 0, k);
    }
}

